const STATUS_COLOR = { green: "#21b85a", amber: "#f4b41a", red: "#e23b2e", na: "#3a3f4b", off: "#3a3f4b" };
const STATUS_LABEL = { green: "Good odds (undersubscribed)", amber: "Tight (decent odds)", red: "Heavily oversubscribed", na: "No Phase 2C intake" };
const YEARS = [2023, 2024, 2025];

export default function SingaporeMap() {
  const mapEl = useRef(null);
  const mapRef = useRef(null);
  const layersRef = useRef({ schools: null, stations: null, lines: null, labels: null, outline: null, green: null });
  const [ready, setReady] = useState(false);
  const [layers, setLayers] = useState({ schools: true, stations: true, lines: true, labels: true, outline: true, green: true, water: true, roads: true });

  // Load Leaflet from CDN
  useEffect(() => {
    if (window.L) { setReady(true); return; }
    const css = document.createElement("link");
    css.rel = "stylesheet";
    css.href = "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css";
    document.head.appendChild(css);
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js";
    s.onload = () => setReady(true);
    document.body.appendChild(s);
  }, []);

  // Init map
  useEffect(() => {
    if (!ready || mapRef.current || !mapEl.current) return;
    const L = window.L;
    const map = L.map(mapEl.current, { zoomControl: true, preferCanvas: true }).setView([1.352, 103.82], 12);
    mapRef.current = map;

    L.tileLayer("https://{s}.basemaps.cartocdn.com/light_nolabels/{z}/{x}/{y}{r}.png", {
      attribution: "© OpenStreetMap contributors © CARTO",
      maxZoom: 19,
    }).addTo(map);

    // ── Singapore coastline outline (grey stroke only) ──
    const outlineGroup = L.layerGroup();
    // Draw each ring as a polyline so there's never any fill or interior crossing
    SG_OUTLINE.forEach((ring) => {
      L.polyline(ring, {
        color: "#888e99", weight: 1.8, opacity: 0.75,
        interactive: false,
      }).addTo(outlineGroup);
    });

    // ── Major roads ──
    const roadGroup = L.layerGroup();
    TRUNK_ROADS.forEach((seg) => {
      L.polyline(seg, { color: "#6b7280", weight: 1, opacity: 0.45, interactive: false }).addTo(roadGroup);
    });
    MAJOR_ROADS.forEach((seg) => {
      L.polyline(seg, { color: "#8b96a8", weight: 2.5, opacity: 0.6, interactive: false }).addTo(roadGroup);
    });

    // ── Green areas ──
    // ── OSM Green spaces ──
    const greenGroup = L.layerGroup();
    OSM_GREEN.forEach((ring) => {
      L.polygon(ring, {
        color: "#3a8f4a", weight: 0.8, opacity: 0.6,
        fillColor: "#4caf60", fillOpacity: 0.22,
        interactive: false,
      }).addTo(greenGroup);
    });

    // ── OSM Water ──
    const waterGroup = L.layerGroup();
    OSM_WATER.forEach((ring) => {
      L.polygon(ring, {
        color: "#2980b9", weight: 0.8, opacity: 0.55,
        fillColor: "#3498db", fillOpacity: 0.30,
        interactive: false,
      }).addTo(waterGroup);
    });
    OSM_RIVERS.forEach((line) => {
      L.polyline(line, {
        color: "#3498db", weight: 1.2, opacity: 0.45,
        interactive: false,
      }).addTo(waterGroup);
    });

    // ── MRT lines ──
    const lineGroup = L.layerGroup();
    Object.values(MRT_LINES).forEach((line) => {
      L.polyline(line.stations.map((s) => [s[1], s[2]]), {
        color: line.color, weight: 4, opacity: 0.85, lineJoin: "round",
      }).addTo(lineGroup);
    });

    // ── MRT stations ──
    const stationGroup = L.layerGroup();
    Object.entries(MRT_LINES).forEach(([code, line]) => {
      line.stations.forEach(([name, lat, lng]) => {
        L.circleMarker([lat, lng], {
          radius: 4, color: "#ffffff", weight: 1.5, fillColor: line.color, fillOpacity: 1,
        }).bindTooltip(`<b>${name}</b><br><span style="color:${line.color}">${code} · ${line.name}</span>`,
          { direction: "top" }).addTo(stationGroup);
      });
    });

    // ── Area labels ──
    const labelGroup = L.layerGroup();
    AREA_LABELS.forEach(([name, lat, lng]) => {
      L.marker([lat, lng], {
        interactive: false,
        icon: L.divIcon({
          className: "area-label",
          html: `<span>${name}</span>`,
          iconSize: [120, 16],
          iconAnchor: [60, 8],
        }),
      }).addTo(labelGroup);
    });

    // ── Schools w/ traffic-light indicators + affiliation badge ──
    const AFFIL_ICON  = { through: "🔗", affiliated: "🤝", mission: "⛪", none: "🎓" };
    const AFFIL_COLOR = { through: "#f59e0b", affiliated: "#818cf8", mission: "#34d399", none: "#94a3b8" };
    const AFFIL_LABEL = { through: "Through-train (P1–S4 same school)", affiliated: "Direct secondary affiliation", mission: "Mission/management body link", none: "No secondary affiliation" };

    const schoolGroup = L.layerGroup();
    SCHOOLS.forEach((sc) => {
      const affType = sc.a || "none";
      const affColor = AFFIL_COLOR[affType];
      const affIcon  = AFFIL_ICON[affType];
      const hasMK    = !!sc.mk;
      const dots = YEARS.map((y, i) => {
        const st = sc.b[i] || "na";
        return `<div class="tl-cell"><div class="tl-dot" style="background:${STATUS_COLOR[st]};box-shadow:0 0 5px ${STATUS_COLOR[st]}88"></div><div class="tl-yr">'${String(y).slice(2)}</div></div>`;
      }).join("");
      // MK badge sits above the traffic-light bar
      const mkBadge = hasMK
        ? `<div class="mk-badge">MK</div>`
        : '';
      const ringStyle = affType !== "none"
        ? `border:2px solid ${affColor};box-shadow:0 0 6px ${affColor}88;`
        : `border:2px solid rgba(80,90,110,.5);`;
      const html = `
        <div class="school-pin">
          ${mkBadge}
          <div class="tl-bar">${dots}</div>
          <div class="school-icon" style="${ringStyle}">${affIcon}</div>
        </div>`;

      const affRow = affType !== "none" ? `
        <div style="margin-top:8px;padding:5px 8px;background:${affColor}18;border-left:3px solid ${affColor};border-radius:3px;font-size:11px;font-family:system-ui">
          <div style="font-weight:700;color:${affColor}">${AFFIL_LABEL[affType]}</div>
          ${sc.s ? `<div style="color:#555;margin-top:2px">↳ ${sc.s}</div>` : ""}
        </div>` : "";

      const mkRow = hasMK ? `
        <div style="margin-top:6px;padding:5px 8px;background:#7c3aed18;border-left:3px solid #7c3aed;border-radius:3px;font-size:11px;font-family:system-ui">
          <div style="font-weight:700;color:#7c3aed">🏫 MOE Kindergarten on-site</div>
          <div style="color:#555;margin-top:2px">K1 & K2 programme within this primary school</div>
        </div>` : "";

      const popup = `
        <div style="font-family:system-ui;min-width:230px">
          <div style="display:flex;align-items:center;gap:6px;margin-bottom:2px">
            <span style="font-size:16px">${affIcon}</span>
            <b style="font-size:13px">${sc.n}</b>
            ${hasMK ? `<span style="background:#7c3aed;color:#fff;font-size:9px;font-weight:700;padding:1px 5px;border-radius:3px;letter-spacing:.5px">MK</span>` : ""}
          </div>
          ${affRow}${mkRow}
          <div style="margin-top:8px;font-size:11px;color:#555;font-weight:600;border-bottom:1px solid #e5e7eb;padding-bottom:4px">Phase 2C P1 Registration</div>
          <table style="margin-top:5px;font-size:11px;border-collapse:collapse;width:100%">
            <tr style="color:#999;font-size:10px">
              <td style="padding:0 6px 3px 0">Year</td>
              <td style="text-align:right;padding:0 6px 3px 0">Vac</td>
              <td style="text-align:right;padding:0 6px 3px 0">App</td>
              <td style="text-align:right;padding:0 0 3px 0">Ballot band</td>
            </tr>
            ${YEARS.map((y, i) => {
              const st = sc.b[i] || "na";
              const det = sc.d ? sc.d[i] : null;
              const vac = det && det.v != null ? det.v : "—";
              const app = det && det.a != null ? det.a : "—";
              const BAND = {"SC<1":"SC <1km","SC1-2":"SC 1–2km","SC>2":"SC >2km","SC<2":"SC <2km","SC<1#":"SC <1km✓","SC<2#":"SC <2km✓","SC#":"SC ✓","PR<1":"PR <1km","PR1-2":"PR 1–2km","PR>2":"PR >2km","PR<1#":"PR <1km✓"};
              let cutoff = "—";
              if (det && det.p != null && det.ba != null) {
                const bandLbl = BAND[det.t] || det.t || "";
                cutoff = `<span style="font-size:9px;color:#888">${bandLbl}</span><br>${det.ba}→${det.bv} <b style="color:${STATUS_COLOR[st]}">${det.p}%</b>`;
              } else if (det && det.t && det.t !== "" && st !== "green" && st !== "na") {
                cutoff = `<span style="color:${STATUS_COLOR[st]};font-weight:700">${BAND[det.t] || det.t}</span>`;
              } else if (st === "green") {
                cutoff = `<span style="color:#21b85a">✓ all in</span>`;
              } else if (st === "na") {
                cutoff = `<span style="color:#bbb">no 2C</span>`;
              }
              const rowBg = st === "red" ? "background:#fff1f0" : st === "amber" ? "background:#fffbeb" : "";
              return `<tr style="${rowBg}">
                <td style="padding:3px 6px 3px 0;color:#444;font-weight:600">${y}</td>
                <td style="text-align:right;padding:3px 6px 3px 0;color:#374151">${vac}</td>
                <td style="text-align:right;padding:3px 6px 3px 0;color:#374151">${app}</td>
                <td style="text-align:right;padding:3px 0;font-size:10px;line-height:1.35">${cutoff}</td>
              </tr>`;
            }).join("")}
          </table>
          <div style="margin-top:5px;font-size:9px;color:#bbb;line-height:1.4">
            Vac/App = 2C seats &amp; total applicants. Ballot band = distance group that balloted (app→seats, success%). Source: sgschooling.com / MOE.
          </div>
        </div>`;

      L.marker([sc.lat, sc.lng], {
        icon: L.divIcon({ className: "school-divicon", html, iconSize: [56, 60], iconAnchor: [28, 56], popupAnchor: [0, -56] }),
      }).bindPopup(popup, { maxWidth: 320 }).addTo(schoolGroup);
    });

    layersRef.current = { schools: schoolGroup, stations: stationGroup, lines: lineGroup, labels: labelGroup, outline: outlineGroup, green: greenGroup, water: waterGroup, roads: roadGroup };
    // z-order: water → green → roads → outline → MRT lines → stations → labels → schools
    waterGroup.addTo(map); greenGroup.addTo(map); roadGroup.addTo(map); outlineGroup.addTo(map);
    lineGroup.addTo(map); stationGroup.addTo(map); labelGroup.addTo(map); schoolGroup.addTo(map);
  }, [ready]);

  // Toggle layers
  useEffect(() => {
    const map = mapRef.current; const refs = layersRef.current;
    if (!map || !refs.schools) return;
    Object.entries(layers).forEach(([k, on]) => {
      const g = refs[k]; if (!g) return;
      if (on && !map.hasLayer(g)) g.addTo(map);
      if (!on && map.hasLayer(g)) map.removeLayer(g);
    });
  }, [layers]);

  const toggle = (k) => setLayers((p) => ({ ...p, [k]: !p[k] }));
  const [minimized, setMinimized] = useState(false);
  const [open, setOpen] = useState({ layers: true, balloting: false, affil: true, mrt: false });
  const toggleSection = (s) => setOpen((p) => ({ ...p, [s]: !p[s] }));

  const sectionBtn = {
    display: "flex", alignItems: "center", justifyContent: "space-between",
    width: "100%", background: "rgba(255,255,255,.04)", border: "1px solid #2e3340",
    borderRadius: 7, padding: "6px 10px", marginBottom: 8, cursor: "pointer",
    color: "#c8cfdc", fontFamily: "system-ui", fontSize: 12, fontWeight: 600,
    letterSpacing: 0.3,
  };

  return (
    <div style={{ position: "relative", width: "100%", height: "100vh", fontFamily: "'Georgia', serif", background: "#1b1d23" }}>
      <style>{`
        .area-label span{ font-family:'Georgia',serif; font-size:11px; letter-spacing:1.5px;
          color:#2a3340; text-shadow:0 0 3px #fff,0 0 3px #fff,0 0 3px #fff; font-weight:700; white-space:nowrap;}
        .green-tip{ background:rgba(47,143,70,.92); color:#fff; border:none; font-family:system-ui;
          font-size:11px; font-weight:600; border-radius:5px; box-shadow:0 2px 8px rgba(0,0,0,.25); }
        .green-tip::before{ display:none; }
        .school-divicon{ background:transparent; border:none; }
        .school-pin{ display:flex; flex-direction:column; align-items:center; }
        .tl-bar{ display:flex; gap:3px; background:rgba(20,22,28,.92); padding:3px 4px; border-radius:5px;
          border:1px solid #3a3f4b; }
        .tl-cell{ display:flex; flex-direction:column; align-items:center; }
        .tl-dot{ width:8px; height:8px; border-radius:50%; }
        .tl-yr{ font-size:6.5px; color:#9aa3b2; margin-top:1px; font-family:system-ui; }
        .school-icon{ font-size:15px; line-height:1; margin-top:2px; filter:drop-shadow(0 1px 2px #000);
          border-radius:50%; width:22px; height:22px; display:flex; align-items:center;
          justify-content:center; background:rgba(255,255,255,.92); }
        .mk-badge{ background:#7c3aed; color:#fff; font-size:7px; font-weight:800;
          letter-spacing:.5px; padding:1px 3px; border-radius:3px; text-align:center;
          margin-bottom:2px; font-family:system-ui; line-height:1.3; }
        .leaflet-popup-content-wrapper{ border-radius:8px; }
      `}</style>

      <div ref={mapEl} style={{ position: "absolute", inset: 0 }} />

      {/* Control panel */}
      <div style={{
        position: "absolute", top: 16, right: 16, zIndex: 1000, width: 258,
        background: "rgba(20,23,30,.96)", color: "#e6e9f0", borderRadius: 13,
        border: "1px solid #2e3340", backdropFilter: "blur(8px)",
        boxShadow: "0 8px 36px rgba(0,0,0,.6)",
        overflow: "hidden",
        transition: "box-shadow .2s",
      }}>
        {/* ── Title bar (always visible) ── */}
        <div style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "12px 14px 10px",
          borderBottom: minimized ? "none" : "1px solid #2e3340",
          cursor: "default",
        }}>
          <div>
            <div style={{ fontSize: 15, fontWeight: 700, letterSpacing: 0.4 }}>🇸🇬 Singapore Map</div>
            {!minimized && (
              <div style={{ fontSize: 10.5, color: "#6e7a90", marginTop: 2, fontFamily: "system-ui" }}>
                MRT · Schools · Areas
              </div>
            )}
          </div>
          <button
            onClick={() => setMinimized(m => !m)}
            title={minimized ? "Expand" : "Minimise"}
            style={{
              background: "rgba(255,255,255,.07)", border: "1px solid #3a4150",
              borderRadius: 7, width: 28, height: 28, cursor: "pointer",
              color: "#9aa3b2", fontSize: 14, display: "flex", alignItems: "center",
              justifyContent: "center", flexShrink: 0, transition: "background .15s",
            }}
          >
            {minimized ? "＋" : "−"}
          </button>
        </div>

        {/* ── Collapsible body ── */}
        {!minimized && (
          <div style={{ padding: "10px 14px 14px" }}>

            {/* ── Layers section ── */}
            <button onClick={() => toggleSection("layers")} style={sectionBtn}>
              <span>Layers</span>
              <span style={{ fontSize: 10, opacity: .7 }}>{open.layers ? "▲" : "▼"}</span>
            </button>
            {open.layers && (
              <div style={{ marginBottom: 8 }}>
                {[
                  ["roads",   "Major roads"],
                  ["outline", "Island outline"],
                  ["water",   "Water bodies"],
                  ["green",   "Green areas"],
                  ["labels",  "Area names"],
                  ["lines",   "MRT lines"],
                  ["stations","MRT stations"],
                  ["schools", "Primary schools"],
                ].map(([k, label]) => (
                  <label key={k} style={{ display: "flex", alignItems: "center", gap: 9, padding: "5px 0", cursor: "pointer", fontFamily: "system-ui", fontSize: 12.5 }}>
                    <input type="checkbox" checked={layers[k] ?? true} onChange={() => toggle(k)} style={{ accentColor: "#21b85a", width: 15, height: 15, flexShrink: 0 }} />
                    {label}
                  </label>
                ))}
              </div>
            )}

            {/* ── Balloting legend ── */}
            <button onClick={() => toggleSection("balloting")} style={sectionBtn}>
              <span>Balloting Odds</span>
              <span style={{ fontSize: 10, opacity: .7 }}>{open.balloting ? "▲" : "▼"}</span>
            </button>
            {open.balloting && (
              <div style={{ marginBottom: 8 }}>
                {[["green","Undersubscribed — all in"],["amber","Tight (≥70% odds)"],["red","Oversubscribed (<70%)"]].map(([s, t]) => (
                  <div key={s} style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 12, fontFamily: "system-ui", marginBottom: 5 }}>
                    <span style={{ width: 10, height: 10, borderRadius: "50%", flexShrink: 0, background: STATUS_COLOR[s], boxShadow: `0 0 5px ${STATUS_COLOR[s]}` }} />
                    {t}
                  </div>
                ))}
                <div style={{ fontSize: 10, color: "#5a6270", marginTop: 6, fontFamily: "system-ui", lineHeight: 1.45 }}>
                  3 dots / school: 2023 · 2024 · 2025. Click a school for details.<br />
                  Source: <span style={{ color: "#7d97c4" }}>sgschooling.com</span> · {SCHOOLS.length} schools
                </div>
              </div>
            )}

            {/* ── Affiliation legend ── */}
            <button onClick={() => toggleSection("affil")} style={sectionBtn}>
              <span>Secondary Affiliation</span>
              <span style={{ fontSize: 10, opacity: .7 }}>{open.affil ? "▲" : "▼"}</span>
            </button>
            {open.affil && (
              <div style={{ marginBottom: 8 }}>
                {[
                  ["🔗", "#f59e0b", "Through-train (P1–S4 same school)", "3 schools — Catholic High, Maris Stella High, CHIJ St Nicholas Girls'"],
                  ["🤝", "#818cf8", "Direct secondary affiliation", "12 schools — named feeder school e.g. RGS→RI, MGS, SCGS"],
                  ["⛪", "#34d399", "Mission / management body link", "18 schools — same CHIJ, Methodist, Anglican, La Salle body"],
                  ["🎓", "#94a3b8", "No secondary affiliation", "Government primary schools"],
                ].map(([icon, color, label, sub]) => (
                  <div key={icon} style={{ display: "flex", alignItems: "flex-start", gap: 8, marginBottom: 8, fontFamily: "system-ui" }}>
                    <div style={{ width: 22, height: 22, borderRadius: "50%", background: "#fff", border: `2px solid ${color}`,
                      boxShadow: `0 0 5px ${color}88`, display: "flex", alignItems: "center", justifyContent: "center",
                      fontSize: 11, flexShrink: 0, marginTop: 1 }}>{icon}</div>
                    <div>
                      <div style={{ fontSize: 12, fontWeight: 600, color: "#d1d8e8" }}>{label}</div>
                      <div style={{ fontSize: 10, color: "#6b7585", marginTop: 1, lineHeight: 1.35 }}>{sub}</div>
                    </div>
                  </div>
                ))}
                <div style={{ fontSize: 10, color: "#5a6270", fontFamily: "system-ui", lineHeight: 1.4 }}>
                  Click any school to see its affiliated secondary.
                </div>
                <div style={{ marginTop: 10, paddingTop: 8, borderTop: "1px solid #2e3340" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, fontFamily: "system-ui" }}>
                    <span style={{ background: "#7c3aed", color: "#fff", fontSize: 8, fontWeight: 800,
                      padding: "1px 4px", borderRadius: 3, letterSpacing: .5, flexShrink: 0 }}>MK</span>
                    <div>
                      <div style={{ fontSize: 12, fontWeight: 600, color: "#d1d8e8" }}>MOE Kindergarten on-site</div>
                      <div style={{ fontSize: 10, color: "#6b7585", marginTop: 1 }}>53 of 182 primary schools host an MK</div>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {/* ── MRT lines ── */}
            <button onClick={() => toggleSection("mrt")} style={sectionBtn}>
              <span>MRT Lines</span>
              <span style={{ fontSize: 10, opacity: .7 }}>{open.mrt ? "▲" : "▼"}</span>
            </button>
            {open.mrt && (
              <div>
                {Object.entries(MRT_LINES).map(([code, l]) => (
                  <div key={code} style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 11.5, fontFamily: "system-ui", marginBottom: 4 }}>
                    <span style={{ width: 18, height: 4, borderRadius: 2, flexShrink: 0, background: l.color }} />
                    <b style={{ color: l.color, minWidth: 30 }}>{code}</b>
                    <span style={{ color: "#9aa3b2" }}>{l.name}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
